import React, { useState, useEffect } from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Profile() {
  // ================= PROFILE STATE =================
  const [profile, setProfile] = useState({
    fullName: "",
    email: "",
    phone: "",
    address: "",
    gender: "",
    dob: "",
  });

  // ================= PASSWORD STATE =================
  const [oldPassword, setOldPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  const [loading, setLoading] = useState(false);

  // ================= LOAD PROFILE =================
  useEffect(() => {
    const fetchProfile = async () => {
      const token = localStorage.getItem("token");

      try {
        const response = await fetch("http://127.0.0.1:8000/profile/", {
          method: "GET",
          headers: {
            Authorization: `Token ${token}`,
          },
        });

        const data = await response.json();

        if (response.ok) {
          setProfile({
            fullName: data.full_name,
            email: data.email,
            phone: data.phone,
            address: data.address,
            gender: data.gender,
            dob: data.dob,
          });
        }
      } catch (error) {
        console.log(error);
      }
    };

    fetchProfile();
  }, []);

  // ================= CHANGE PASSWORD =================
  const handleChangePassword = async () => {
    if (!oldPassword || !newPassword || !confirmPassword) {
      alert("All fields required");
      return;
    }

    if (newPassword !== confirmPassword) {
      alert("Passwords do not match");
      return;
    }

    const token = localStorage.getItem("token");

    setLoading(true);

    try {
      const response = await fetch(
        "http://127.0.0.1:8000/change-password/",
        {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Token ${token}`,
          },
          body: JSON.stringify({
            old_password: oldPassword,
            new_password: newPassword,
          }),
        }
      );

      const data = await response.json();

      if (response.ok) {
        alert("Password updated successfully");

        setOldPassword("");
        setNewPassword("");
        setConfirmPassword("");
      } else {
        alert(data.error);
      }
    } catch (error) {
      alert("Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <h2>My Profile</h2>

        <div style={styles.wrapper}>
          {/* ================= PROFILE SECTION ================= */}
          <div style={styles.card}>
            <h3>Personal Details</h3>

            <p><b>Name:</b> {profile.fullName}</p>
            <p><b>Email:</b> {profile.email}</p>
            <p><b>Phone:</b> {profile.phone}</p>
            <p><b>Address:</b> {profile.address || "Not added"}</p>
            <p><b>Gender:</b> {profile.gender || "Not added"}</p>
            <p><b>Date of Birth:</b> {profile.dob || "Not added"}</p>
          </div>

          {/* ================= PASSWORD SECTION ================= */}
          <div style={styles.card}>
            <h3>Change Password</h3>

            <input
              type="password"
              placeholder="Old Password"
              value={oldPassword}
              onChange={(e) => setOldPassword(e.target.value)}
              style={styles.input}
            />

            <input
              type="password"
              placeholder="New Password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              style={styles.input}
            />

            <input
              type="password"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              style={styles.input}
            />

            <button onClick={handleChangePassword} style={styles.btn}>
              {loading ? "Updating..." : "Update Password"}
            </button>
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Profile;

/* ================= STYLES ================= */
const styles = {
  container: {
    fontFamily: "Arial",
  },

  main: {
    padding: "40px",
    textAlign: "center",
  },

  wrapper: {
    display: "flex",
    justifyContent: "center",
    gap: "30px",
    marginTop: "30px",
    flexWrap: "wrap",
  },

  card: {
    width: "350px",
    padding: "20px",
    boxShadow: "0 0 10px #ccc",
    borderRadius: "10px",
    backgroundColor: "#fff",
  },

  input: {
    width: "100%",
    marginBottom: "10px",
    padding: "10px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  btn: {
    width: "100%",
    padding: "10px",
    backgroundColor: "#3498db",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
